function solve(points) {
    const MOD = 1e9 + 7;
    const yToXs = new Map();

    for (const [x, y] of points) {
        if (!yToXs.has(y)) {
            yToXs.set(y, []);
        }
        yToXs.get(y).push(x);
    }

    let res = 0;
    const yList = Array.from(yToXs.keys());

    for (const y of yList) {
        const xs = yToXs.get(y);
        if (xs.length < 2) continue;
        xs.sort((a, b) => a - b);
    }

    for (let i = 0; i < yList.length; i++) {
        const y1 = yList[i];
        const xs1 = yToXs.get(y1);
        const m = xs1.length;
        if (m < 2) continue;

        for (let j = i + 1; j < yList.length; j++) {
            const y2 = yList[j];
            const xs2 = yToXs.get(y2);
            const n = xs2.length;
            if (n < 2) continue;

            let left1 = 0, left2 = 0;
            let pairs = 0;

            while (left1 < m - 1 && left2 < n - 1) {
                const x1 = xs1[left1];
                const x1Next = xs1[left1 + 1];
                const x2 = xs2[left2];
                const x2Next = xs2[left2 + 1];

                if (x1Next - x1 === x2Next - x2) {
                    const count1 = 1;
                    const count2 = 1;

                    while (left1 + count1 < m - 1 && xs1[left1 + count1 + 1] - xs1[left1 + count1] === x1Next - x1) {
                        count1++;
                    }

                    while (left2 + count2 < n - 1 && xs2[left2 + count2 + 1] - xs2[left2 + count2] === x2Next - x2) {
                        count2++;
                    }

                    pairs += count1 * count2;
                    left1 += count1;
                    left2 += count2;
                } else if (x1Next - x1 < x2Next - x2) {
